          { question: 'What does instance segmentation do?', options: ['Labels the whole image', 'Draws bounding boxes', 'Identifies precise pixel-level outlines of each object', 'Detects motion'], answer: 2 },
          { question: 'Which medical imaging task has AI shown strong performance on?', options: ['Performing surgery', 'Detecting cancer in X-rays and CT scans', 'Prescribing medication', 'Drawing blood'], answer: 1 },
          { question: 'What is a concern with facial recognition technology?', options: ['It is too slow for practical use', 'Privacy and civil liberties implications', 'It only works with high-resolution cameras', 'It cannot be used on smartphones'], answer: 1 }
